    // Admin mock bypass for EMS default setup
    if (email === 'admin@123.com' && password === 'EMS' && expectedRole === 'admin') {
      setUser({ id: 'mock-admin-id', email: 'admin@123.com', user_metadata: { full_name: 'System Admin' } });
      setRole('admin');
      return { data: { user: { id: 'mock-admin-id' } }, error: null };
    }

    const { data, error } = await supabase.auth.signInWithPassword({ email, password });

    if (error) {
      return { data, error: { message: "Invalid credentials. Please check your email and password." } };
    }

    if (data?.user) {
      const { data: profileData, error: profileError } = await supabase
        .from('profiles')
        .select('role')
        .eq('id', data.user.id)
        .single();

      if (profileError || profileData?.role !== expectedRole) {
        await supabase.auth.signOut();
        setUser(null);
        setRole(null);
        return { data: null, error: { message: "Access Denied: Unauthorized Role Selection" } };
      }
      setRole(profileData.role);
    }
    return { data, error };
  };

  const logout = async () => {
    if (user?.id === 'mock-admin-id') {
      setUser(null);
      setRole(null);
      return;
    }
    const { error } = await supabase.auth.signOut();
    if (error) console.error("Error signing out:", error.message);
  };

  const registerEmployee = async (email, password, fullName) => {
    const { data: authData, error: authError } = await supabase.auth.signUp({
        email,
        password,
        options: { data: { full_name: fullName } }
    });

    if (authError) return { error: authError };

    if (authData?.user) {
        const { error: profileError } = await supabase
            .from('profiles')
            .insert([{ id: authData.user.id, email, full_name: fullName, role: 'employee' }]);
        if (profileError) return { error: profileError };
    }
    return { data: authData, error: null };
  };

  const deleteEmployee = async (employeeId) => {
    const { error } = await supabase
        .from('profiles')
        .delete()
        .eq('id', employeeId);
    return { error };
  };

  const value = {
    user,
    role,
    login,
    logout,
    loading,
    registerEmployee,
    deleteEmployee
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

export default AuthContext;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabase } from '../utils/supabaseClient';
import { useAuth } from './AuthContext';

const TaskContext = createContext();

export const useTask = () => useContext(TaskContext);

export const TaskProvider = ({ children }) => {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user, role } = useAuth();

  const fetchTasks = async () => {
    if (!user) return;
    setLoading(true);

    // Direct select from tasks, avoiding complex aliases that cause PGRST205
    let query = supabase.from('tasks').select('*, profiles(full_name, email)');

    if (role === 'employee') {
      query = query.eq('assigned_to_id', user.id);
    }

    const { data, error } = await query.order('created_at', { ascending: false });

    if (error) {
      console.error("Error fetching tasks:", error.message);
    } else {
      setTasks(data || []);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchTasks();

    if (!user) return;

    // Real-time listener for tasks
    const subscription = supabase
      .channel('public:tasks')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'tasks' }, (payload) => {
        fetchTasks(); // Refetch to ensure we get joined profile data safely
      })
      .subscribe();

    return () => supabase.removeChannel(subscription);
  }, [user, role]);

  const createTask = async (taskData) => {
    const { data, error } = await supabase
      .from('tasks')
      .insert([{ ...taskData, created_by: user.id }])
      .select();

    if (error) {
      console.error("Error creating task:", error.message);
      return { error };
    }
    return { data };
  };

  const updateTaskStatus = async (taskId, newStatus) => {
    const { data, error } = await supabase
      .from('tasks')
      .update({ status: newStatus })
      .eq('id', taskId)
      .select();

    if (error) {
      console.error("Error updating status:", error.message);
      return { error };
    }
    return { data };
  };

  return (
    <TaskContext.Provider value={{ tasks, loading, fetchTasks, createTask, updateTaskStatus }}>
      {children}
    </TaskContext.Provider>
  );
};

export default TaskContext;
